  ('palavra-de-poder-fortificar', 'Palavra de Poder: Fortificar', 7, '7º Círculo', (SELECT id FROM rpg.phb_spell_school WHERE slug = 'encantamento'), 'Ação', '18 metros', TRUE, FALSE, FALSE, NULL, 'V', 'Instantânea', FALSE, FALSE, 'Você fortalece até seis criaturas à sua vista e no alcance da magia. A magia concede 120 Pontos de Vida Temporários, que você divide entre os alvos da magia.', NULL, (SELECT id FROM rpg.phb_source_citation WHERE slug = 'phb-2024-pt:ch7:241-349')),
  ('palavra-de-poder-matar', 'Palavra de Poder: Matar', 9, '9º Círculo', (SELECT id FROM rpg.phb_spell_school WHERE slug = 'encantamento'), 'Ação', '18 metros', TRUE, FALSE, FALSE, NULL, 'V', 'Instantânea', FALSE, FALSE, 'Você obriga uma criatura à sua vista e no alcance da magia a morrer. Se o alvo tiver 100 Pontos de Vida ou menos, ele morre. Caso contrário, sofre 12d12 pontos de dano Psíquico.', NULL, (SELECT id FROM rpg.phb_source_citation WHERE slug = 'phb-2024-pt:ch7:241-349')),
  ('palavra-de-poder-salvar', 'Palavra de Poder: Salvar', 9, '9º Círculo', (SELECT id FROM rpg.phb_spell_school WHERE slug = 'encantamento'), 'Ação', '18 metros', TRUE, FALSE, FALSE, NULL, 'V', 'Instantânea', FALSE, FALSE, 'Uma onda de energia curativa percorre uma criatura
